index 2d7524e8018b..da893785a184 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1337,7 +1337,6 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
       V2 = X;
   }
-
   // Look through and with a negative power of 2 mask on V1 or V2. This
   // detects idioms of the form `(x == A) || ((x & Mask) == A + 1)` where A + 1
   // is aligned to the mask and A + 1 >= |Mask|. This pattern corresponds to a
@@ -1367,25 +1366,72 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     }
   }

+  // Try to look through and with a non-negated-power-of-2 constant mask on V1
+  // or V2 for equality comparisons that are not covered by the pattern above.
+  // This handles patterns like:
+  //   (icmp ult x, C1) & (icmp eq (x & M), C2)
+  // where M is a mask that clears only low bits, so the masked comparison
+  // corresponds to a contiguous range of x values.
+  // Note: m_NegatedPower2 is the same mask shape (e.g., -2, -4, -8, etc.)
+  // but the pattern above additionally requires specific predicates (NE/NE for
+  // AND, EQ/EQ for OR) and constant relationships.
+  const APInt *AndMask1 = nullptr, *AndMask2 = nullptr;
+  bool MatchAndMask1 = false, MatchAndMask2 = false;
+  if (V1 != V2 && !MatchedAnd1 && !MatchedAnd2) {
+    Value *X;
+    if (ICmpInst::isEquality(Pred1) &&
+        match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(AndMask1))))) {
+      MatchAndMask1 = true;
+      V1 = X;
+    }
+    if (ICmpInst::isEquality(Pred2) &&
+        match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(AndMask2))))) {
+      MatchAndMask2 = true;
+      V2 = X;
+    }
+  }
+
   if (V1 != V2)
     return nullptr;

+  auto getRangeForMaskedICmp = [](CmpPredicate Pred, const APInt &C,
+                                  const APInt &Mask) -> ConstantRange {
+    unsigned BW = C.getBitWidth();
+    APInt NotM = ~Mask;
+    // C can only have bits in Mask for the comparison to be satisfiable.
+    if ((C & NotM) != 0)
+      return Pred == ICmpInst::ICMP_EQ ? ConstantRange::getEmpty(BW)
+                                       : ConstantRange::getFull(BW);
+    APInt NotMPlus1 = NotM + 1;
+    if (Pred == ICmpInst::ICMP_EQ)
+      return ConstantRange(C, C + NotMPlus1);
+    assert(Pred == ICmpInst::ICMP_NE && "Expected EQ or NE predicate");
+    return ConstantRange(C + NotMPlus1, C);
+  };
+
   ConstantRange CR1 =
       MatchedAnd1
           ? ConstantRange(*C1, *C1 - *Mask1)
-          : ConstantRange::makeExactICmpRegion(
-                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+          : MatchAndMask1
+                ? getRangeForMaskedICmp(
+                      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1,
+                      *C1, *AndMask1)
+                : ConstantRange::makeExactICmpRegion(
+                      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);

   ConstantRange CR2 =
       MatchedAnd2
           ? ConstantRange(*C2, *C2 - *Mask2)
-          : ConstantRange::makeExactICmpRegion(
-                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+          : MatchAndMask2
+                ? getRangeForMaskedICmp(
+                      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2,
+                      *C2, *AndMask2)
+                : ConstantRange::makeExactICmpRegion(
+                      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);
-
   Type *Ty = V1->getType();
   Value *NewV = V1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);

